solution: ```class Solution {
public:
    string solveEquation(string equation) {
        int a = 0, b = 0, sign = 1, i = 0;
        auto parse = [&](bool left) {
            int val = 0, coef = 0;
            int curSign = left ? sign : -sign;
            while (i < equation.size() && equation[i] != '=') {
                if (equation[i] == '+' || equation[i] == '-') {
                    curSign = (equation[i] == '+') ? (left ? sign : -sign) : (left ? -sign : sign);
                    i++;
                }
                val = 0;
                bool hasNum = false;
                while (i < equation.size() && isdigit(equation[i])) {
                    val = val * 10 + (equation[i] - '0');
                    hasNum = true;
                    i++;
                }
                if (i < equation.size() && equation[i] == 'x') {
                    if (hasNum) coef += curSign * val;
                    else coef += curSign;
                    i++;
                } else {
                    b -= curSign * val;
                }
            }
            a += coef;
        };
        parse(true);
        i++;
        sign = 1;
        parse(false);
        if (a == 0) {
            if (b == 0) return "Infinite solutions";
            else return "No solution";
        }
        return "x=" + to_string(b / a);
    }
};```
